// // This module implements an active-high isolation gate. The output X is asserted when the input A is low and the SLEEP signal is high (active). When SLEEP is low (inactive), the output X is driven high, effectively isolating the input from the output during sleep mode.
module top_module(
    X    ,
    A    ,
    SLEEP
);// Module ports
    output X    ;
    input  A    ;
    input  SLEEP;

    // Module supplies
    supply1 KAPWR;
    supply0 VGND ;
    supply1 VPB  ;
    supply0 VNB  ;

    // Local signals
    wire sleepn;

    //  Name  Output  Other arguments
    not not0 (sleepn, SLEEP          );
    and and0 (X     , A, sleepn      );

endmodule
